#include <stdio.h>
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, minX, maxX;
        scanf("%d %d %d", &N, &minX, &maxX);
        int weights[N], biases[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &weights[i], &biases[i]);
        }
        int nonSpammers = 0, spammers = 0;
        for (int x = minX; x <= maxX; x++) {
            int output = x;
            for (int i = 0; i < N; i++) {
                output = weights[i] * output + biases[i];
            }
            if (output % 2 == 0) {
                nonSpammers++;
            } else {
                spammers++;
            }
        }
        printf("%d %d\n", nonSpammers, spammers);
    }
    return 0;
}

