const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;
const readline = () => lines[idx++];
const T = parseInt(readline());
for (let i = 0; i < T; i++) {
    const [N, minX, maxX] = readline().split(' ').map(Number);
    const weights = [];
    const biases = [];
    for (let j = 0; j < N; j++) {
        const [w, b] = readline().split(' ').map(Number);
        weights.push(w);
        biases.push(b);
    }
    let nonSpammers = 0;
    let spammers = 0;
    for (let x = minX; x <= maxX; x++) {
        let output = x;
        for (let j = 0; j < N; j++) {
            output = weights[j] * output + biases[j];
        }
        if (output % 2 === 0) {
            nonSpammers++;
        } else {
            spammers++;
        }
    }
    console.log(nonSpammers + ' ' + spammers);
}
